import React, { useEffect } from "react";
import "./App.css";
import Branch from "branch-sdk";

function App() {
  useEffect(() => {
    Branch.init("key_live_bsjE473F5T8mSmifKQzMjjfdDubO8VTj");
  });
  const handleEventTracking = (eventName) => {
    Branch.logEvent(eventName);
  };
  return (
    <div className="container">
      <div className="button-row">
        <button
          className="button"
          onClick={() => handleEventTracking("VIEW_ITEM")}
        >
          View item
        </button>
        <button
          className="button"
          onClick={() => handleEventTracking("ADD_TO_CART")}
        >
          Add to cart
        </button>
        <button
          className="button"
          onClick={() => handleEventTracking("INITIATE_PURCHASE")}
        >
          Init Purchase
        </button>
        <button
          className="button"
          onClick={() => handleEventTracking("PURCHASE")}
        >
          Purchase
        </button>
        <button
          className="button"
          onClick={() => handleEventTracking("COMPLETE_REGISTRATION")}
        >
          Register
        </button>
      </div>
    </div>
  );
}

export default App;
